package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClassMock;

  @BeforeAll
  static void setup() {
    recordClassMock = RecordClassMock.class;
  }

  @Test
  void testGetRecordComponentNames_returnsExpectedNames() throws Exception {
    // Use reflection to access private static field RECORD_HELPER
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    Object originalRecordHelper = recordHelperField.get(null);

    // Create a mock of the same class as RECORD_HELPER
    Object recordHelperMock = mock(originalRecordHelper.getClass());

    try (MockedStatic<ReflectionHelper> reflectionHelperStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      // Replace the private static RECORD_HELPER field with our mock using reflection
      recordHelperField.set(null, recordHelperMock);

      String[] expected = new String[] {"component1", "component2"};
      when(recordHelperMock.getClass()
          .getMethod("getRecordComponentNames", Class.class)
          .invoke(recordHelperMock, recordClassMock)).thenReturn(expected);

      // Because we cannot stub invoke directly, better to stub the method on mock directly:
      when(recordHelperMock.getClass()
          .getMethod("getRecordComponentNames", Class.class)
          .invoke(recordHelperMock, recordClassMock)).thenReturn(expected);

      // Instead, use doReturn to stub the method on the mock
      // But since recordHelperMock is Object, cast to its class
      var recordHelperClass = recordHelperMock.getClass();
      var method = recordHelperClass.getMethod("getRecordComponentNames", Class.class);
      // Use Mockito spy on recordHelperMock to stub method
      Object spy = spy(recordHelperMock);
      doReturn(expected).when(spy).getRecordComponentNames(recordClassMock);

      // Set RECORD_HELPER to spy
      recordHelperField.set(null, spy);

      String[] actual = ReflectionHelper.getRecordComponentNames(recordClassMock);

      assertArrayEquals(expected, actual);

      verify(spy).getRecordComponentNames(recordClassMock);
    } finally {
      // Restore original RECORD_HELPER field value
      recordHelperField.set(null, originalRecordHelper);
    }
  }

  // Dummy class to simulate a record (cannot use 'record' keyword)
  private static class RecordClassMock {
    private final String component1;
    private final int component2;

    public RecordClassMock(String component1, int component2) {
      this.component1 = component1;
      this.component2 = component2;
    }

    public String component1() {
      return component1;
    }

    public int component2() {
      return component2;
    }
  }
}
